dashboard.definition:
{
  "title": "Source - M365 Audit",
  "description": "Microsoft 365 management activity — detect data exfiltration, insider threats, unauthorized file sharing",
  "dataSources": {
    "ds_total_events": {
      "type": "ds.search",
      "name": "Total M365 Audit Events Over Time",
      "options": {
        "query": "| tstats count where index=fake_tshrt sourcetype=\"FAKE:o365:management:activity\" by _time span=1h"
      }
    },
    "ds_file_operations": {
      "type": "ds.search",
      "name": "File Operations",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:o365:management:activity\" Operation IN (\"FileAccessed\", \"FileModified\", \"FileDeleted\", \"FileCopied\", \"FileMoved\", \"FileDownloaded\", \"FileUploaded\", \"FileRenamed\") | stats count"
      }
    },
    "ds_unique_users": {
      "type": "ds.search",
      "name": "Unique Users",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:o365:management:activity\" UserId=* | stats dc(UserId) as count"
      }
    },
    "ds_external_sharing": {
      "type": "ds.search",
      "name": "External Sharing Events",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:o365:management:activity\" Operation IN (\"SharingSet\", \"AnonymousLinkCreated\", \"SharingInvitationCreated\", \"AddedToSecureLink\") | stats count"
      }
    },
    "ds_events_over_time": {
      "type": "ds.search",
      "name": "Activity Over Time by Operation",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:o365:management:activity\" | timechart span=1h count by Operation limit=8"
      }
    },
    "ds_events_by_workload": {
      "type": "ds.search",
      "name": "Events by Workload",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:o365:management:activity\" Workload=* | stats count by Workload | sort -count"
      }
    },
    "ds_top_users": {
      "type": "ds.search",
      "name": "Top Users by Activity Volume",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:o365:management:activity\" UserId=* | stats count by UserId | sort -count | head 15 | rename UserId as \"User\""
      }
    },
    "ds_sample_events": {
      "type": "ds.search",
      "name": "Recent File Sharing/Access Events",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:o365:management:activity\" | table _time UserId Operation Workload ObjectId | sort -_time | head 30 | rename UserId as \"User\" Operation as \"Operation\" Workload as \"Workload\" ObjectId as \"Object\""
      }
    }
  },
  "visualizations": {
    "viz_header": {
      "type": "splunk.markdown",
      "options": {
        "markdown": "# Source — M365 Audit\n\n**Sourcetype:** `FAKE:o365:management:activity` | **Coverage:** SharePoint, Exchange, Azure AD user operations | **Format:** JSON\n\n**Why monitor?** Detect data exfiltration via unauthorized file sharing, identify insider threats through abnormal activity patterns, and maintain compliance audit trails.",
        "fontColor": "#C3CBD4"
      }
    },
    "viz_kpi_total_events": {
      "type": "splunk.singlevalue",
      "title": "Total Activities",
      "dataSources": { "primary": "ds_total_events" },
      "options": {
        "majorValue": "> sparklineValues | lastPoint()",
        "sparklineValues": "> primary | seriesByName('count')",
        "sparklineDisplay": "below",
        "majorColor": "#00D2FF",
        "backgroundColor": "transparent",
        "showSparklineAreaGraph": true,
        "sparklineStrokeColor": "#00D2FF"
      }
    },
    "viz_kpi_file_operations": {
      "type": "splunk.singlevalue",
      "title": "File Operations",
      "dataSources": { "primary": "ds_file_operations" },
      "options": {
        "majorValue": "> primary | seriesByName('count') | lastPoint()",
        "majorColor": "#7B56DB",
        "backgroundColor": "transparent",
        "sparklineDisplay": "off"
      }
    },
    "viz_kpi_unique_users": {
      "type": "splunk.singlevalue",
      "title": "Unique Users",
      "dataSources": { "primary": "ds_unique_users" },
      "options": {
        "majorValue": "> primary | seriesByName('count') | lastPoint()",
        "majorColor": "#53A051",
        "backgroundColor": "transparent",
        "sparklineDisplay": "off"
      }
    },
    "viz_kpi_external_sharing": {
      "type": "splunk.singlevalue",
      "title": "External Sharing Events",
      "dataSources": { "primary": "ds_external_sharing" },
      "options": {
        "majorValue": "> primary | seriesByName('count') | lastPoint()",
        "majorColor": "#DC4E41",
        "backgroundColor": "transparent",
        "sparklineDisplay": "off"
      }
    },
    "viz_events_over_time": {
      "type": "splunk.area",
      "title": "Activity Over Time by Operation",
      "dataSources": { "primary": "ds_events_over_time" },
      "options": {
        "stackMode": "stacked",
        "legendDisplay": "right",
        "nullValueDisplay": "zero",
        "areaOpacity": 0.7,
        "backgroundColor": "transparent",
        "xAxisTitleVisibility": "hide",
        "yAxisTitleText": "Events / hour",
        "yAxisTitleVisibility": "show",
        "yAxisAbbreviation": "auto",
        "seriesColors": ["#53A051", "#00D2FF", "#DC4E41", "#F8BE34", "#7B56DB", "#009CEB", "#F1813F", "#00CDAF"]
      },
      "showProgressBar": true,
      "showLastUpdated": true
    },
    "viz_events_by_workload": {
      "type": "splunk.pie",
      "title": "Events by Workload",
      "dataSources": { "primary": "ds_events_by_workload" },
      "options": {
        "labelDisplay": "valuesAndPercentage",
        "showDonutHole": true,
        "seriesColors": ["#53A051", "#00D2FF", "#DC4E41", "#F8BE34", "#7B56DB", "#009CEB", "#F1813F", "#00CDAF"]
      }
    },
    "viz_top_users": {
      "type": "splunk.bar",
      "title": "Top Users by Activity Volume",
      "dataSources": { "primary": "ds_top_users" },
      "options": {
        "seriesColors": ["#00D2FF"],
        "legendDisplay": "off",
        "xAxisTitleText": "Activities",
        "xAxisTitleVisibility": "show",
        "yAxisTitleVisibility": "hide",
        "backgroundColor": "transparent"
      },
      "showProgressBar": true
    },
    "viz_sample_header": {
      "type": "splunk.markdown",
      "options": {
        "markdown": "### Recent File Sharing / Access Events",
        "fontColor": "#C3CBD4"
      }
    },
    "viz_sample_events": {
      "type": "splunk.table",
      "title": "Recent Events",
      "dataSources": { "primary": "ds_sample_events" },
      "options": {
        "count": 20,
        "showRowNumbers": false
      },
      "showProgressBar": true,
      "showLastUpdated": true
    }
  },
  "inputs": {
    "input_global_trp": {
      "type": "input.timerange",
      "title": "Time Range",
      "options": {
        "token": "global_time",
        "defaultValue": "1767225600,1769904000"
      }
    }
  },
  "defaults": {
    "dataSources": {
      "ds.search": {
        "options": {
          "queryParameters": {
            "earliest": "$global_time.earliest$",
            "latest": "$global_time.latest$"
          }
        }
      }
    }
  },
  "layout": {
    "type": "grid",
    "globalInputs": ["input_global_trp"],
    "structure": [
      { "item": "viz_header", "type": "block", "position": { "x": 0, "y": 0, "w": 1200, "h": 150 } },
      { "item": "viz_kpi_total_events", "type": "block", "position": { "x": 0, "y": 150, "w": 300, "h": 120 } },
      { "item": "viz_kpi_file_operations", "type": "block", "position": { "x": 300, "y": 150, "w": 300, "h": 120 } },
      { "item": "viz_kpi_unique_users", "type": "block", "position": { "x": 600, "y": 150, "w": 300, "h": 120 } },
      { "item": "viz_kpi_external_sharing", "type": "block", "position": { "x": 900, "y": 150, "w": 300, "h": 120 } },
      { "item": "viz_events_over_time", "type": "block", "position": { "x": 0, "y": 270, "w": 750, "h": 350 } },
      { "item": "viz_events_by_workload", "type": "block", "position": { "x": 750, "y": 270, "w": 450, "h": 350 } },
      { "item": "viz_top_users", "type": "block", "position": { "x": 0, "y": 620, "w": 1200, "h": 300 } },
      { "item": "viz_sample_header", "type": "block", "position": { "x": 0, "y": 920, "w": 1200, "h": 50 } },
      { "item": "viz_sample_events", "type": "block", "position": { "x": 0, "y": 970, "w": 1200, "h": 400 } }
    ]
  }
}
